'use client';

import { AdminNav } from '@/components/AdminNav';
import { RequireAuth } from '@/components/RequireAuth';
import { adminApi } from '@/lib/api';
import { useState } from 'react';

export default function ShiftsPage() {
  const [opening, setOpening] = useState(100000);
  const [closing, setClosing] = useState(100000);
  const [msg, setMsg] = useState('');

  return (
    <RequireAuth>
      <main>
        <AdminNav />
        <div className="card">
          <h1>Shifts</h1>
          <div className="grid2">
            <input type="number" value={opening} onChange={(e) => setOpening(Number(e.target.value))} />
            <button onClick={async () => { const r: any = await adminApi.shiftOpen(opening); setMsg(`Shift open #${r.shift_id}`); }}>Open Shift</button>
          </div>
          <div className="grid2" style={{ marginTop: 8 }}>
            <input type="number" value={closing} onChange={(e) => setClosing(Number(e.target.value))} />
            <button onClick={async () => { const r: any = await adminApi.shiftClose(closing); setMsg(`Shift close #${r.shift_id} variance ${r.variance_cash ?? 0}`); }}>Close Shift</button>
          </div>
          <p className="small">{msg}</p>
        </div>
      </main>
    </RequireAuth>
  );
}
